import sys

class Solution:
    def longestPalindrome(self, s: str) -> int:
        n = len(s)
        dp = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n):
            dp[i][i] = 1
        for len_ in range(2, n + 1):
            for i in range(n - len_ + 1):
                j = i + len_ - 1
                if s[i] == s[j] and len_ == 2:
                    dp[i][j] = 2
                elif s[i] == s[j]:
                    dp[i][j] = dp[i + 1][j - 1] + 2
                else:
                    dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])
        result = 0
        for i in range(n):
            for j in range(n):
                if i <= j and dp[i][j] > result:
                    result = dp[i][j]
        k = 0
        while k < n and s[k] == s[n - 1 - k]:
            k += 1
        return result + k

